{
  "name": "テスト一郎03",
  "talent": {
    "axis1": {
      "name": "構造化",
      "english": "Structural Thinking",
      "description": "複雑な問題を分解し、再現可能な仕組みとして組み立て直す力",
      "items": ["問題を分解する", "仕組みを設計する", "抽象化する", "段取りする"],
      "percentage": 45,
      "top5": ["問題を分解する", "仕組みを設計する", "抽象化する"]
    },
    "axis2": {
      "name": "探求力",
      "english": "Deep Investigation",
      "description": "答えが見えなくても手を止めず、本質に辿り着くまで調べ続ける力",
      "items": ["粘り強く調べる", "集中する"],
      "percentage": 30,
      "top5": ["粘り強く調べる"]
    },
    "axis3": {
      "name": "精緻化",
      "english": "Refinement",
      "description": "余分を削り落とし、本質だけを残した形に整える力",
      "items": ["無駄を省く", "教える", "文章を書く"],
      "percentage": 25,
      "top5": ["無駄を省く"]
    }
  },
  "value": {
    "axis1": {
      "name": "知的誠実",
      "english": "Intellectual Integrity",
      "description": "論理と誠実さを軸に、誤魔化しのない思考と行動を選び続ける",
      "items": ["論理", "誠実", "正確さ", "公平"],
      "percentage": 40,
      "top5": ["論理", "誠実"]
    },
    "axis2": {
      "name": "自律探究",
      "english": "Autonomous Inquiry",
      "description": "誰かに言われるまでもなく、自分の問いを持ち深め続ける姿勢",
      "items": ["探究", "自律", "成長"],
      "percentage": 35,
      "top5": ["探究", "自律"]
    },
    "axis3": {
      "name": "効率設計",
      "english": "Efficiency Design",
      "description": "複雑なものをシンプルに整え、無駄のない構造を美しいと感じる感覚",
      "items": ["効率", "シンプルさ"],
      "percentage": 25,
      "top5": ["効率"]
    }
  },
  "passion": {
    "axis1": {
      "name": "システム構築",
      "english": "System Building",
      "description": "動く仕組みを設計し、現実に実装することへの止まらない衝動",
      "items": ["プログラミング", "システム設計", "自動化"],
      "percentage": 50,
      "top5": ["プログラミング", "システム設計", "自動化"]
    },
    "axis2": {
      "name": "知識共有",
      "english": "Knowledge Sharing",
      "description": "技術の知恵を開かれた形で世界に渡し続けることへの喜び",
      "items": ["オープンソース", "技術書"],
      "percentage": 35,
      "top5": ["オープンソース", "技術書"]
    },
    "axis3": {
      "name": "没入体験",
      "english": "Immersive Experience",
      "description": "コーヒー・登山・ボードゲームに宿る、深く集中する時間への愛着",
      "items": ["コーヒー", "登山", "ボードゲーム"],
      "percentage": 15,
      "top5": []
    }
  },
  "core_words": {
    "talent_core": "仕組みを設計する",
    "value_core": "探究",
    "passion_core": "システム設計"
  },
  "kakuchiiki": "探究心で仕組みを設計して技術の土台をつくり続ける人",
  "kakuchiiki_options": [
    "誠実に問題を分解してシステム設計を形にする人",
    "自律した探究で自動化の仕組みを社会に根付かせる人",
    "論理と効率でオープンソースの技術基盤を設計する人"
  ],
  "insight": "あなたの頭の中には、まだ誰も見ていない設計図がある。それを「形にしきれずに終わること」が一番悔しいと感じるその感覚こそ、才覚の核心だ。問題を分解し、仕組みを設計し、無駄を省く——この3つが重なる瞬間、あなたは義務ではなく本能で動いている。10年後、あなたが書いたコードや育てた後輩が「当たり前の土台」として現場に生きている。派手さはない。けれど、社会が静かに動き続けるための骨格を、あなたが設計した。その地図は、あなたにしか描けない。",
  "what": {
    "products": [
      "日常業務の繰り返し作業を自動化するスクリプトを1本書いて公開する",
      "自分が設計した仕組みや思考プロセスをGitHubまたはZennで技術記事として体系化する",
      "後輩や同僚向けに「問題を分解して設計する思考法」をまとめた技術勉強会を開く",
      "オープンソースプロジェクトに設計レビューや仕組みの改善提案で継続的に貢献する",
      "自分が「こう作れば世界が楽になる」と思い続けてきたシステムを、技術書または実装として世に出す"
    ],
    "actions": "今夜、頭の中にある「こう作れば楽になる」という設計をテキストファイルに書き出す。完成しなくていい。設計図の最初の1行を引く。",
    "offer": "世界中の誰かが今日も手作業で消耗している。あなたが設計した仕組みが走り出した瞬間、その人の時間が永遠に返ってくる。"
  },
  "reward": {
    "economic": "技術記事・オープンソースの実績が積み上がり、設計顧問・技術研修・教材販売の収益が自動化された仕組みのように静かに回り続ける",
    "social": "自分が書いた一行のコードが、会ったこともない誰かの現場で毎朝動いている——その瞬間があなたの人生のターニングポイントになる",
    "intrinsic": "気づいたらまた設計している。誰に頼まれたわけでもなく、「もっとシンプルにできる」という感覚が止まらない。それがあなたの呼吸だ。",
    "model": "探究で設計した仕組みが技術の土台として社会に残り、学びを求める人たちがその知恵にお金と信頼を払い続ける——これがあなたの生き方になる。"
  }
}
